/*
 * lora_field_station.ino — LoRa Environmental Field Station
 *
 * Elements:
 *   1. BME280 I²C Sensor              — T / RH / P on wakeup
 *   2. SX1276 LoRa (RFM95W)          — packet Tx after reading
 *   3. MCU Deep-Sleep (WDT 8 s × 37) — 5-min duty cycle
 *   4. Solar + LiFePO₄ MPPT          — power system (hardware, no code)
 *   5. MicroSD Logger                 — CSV backup per reading
 *   6. Arduino Pro Mini 3.3 V         — orchestrator
 *
 * Average current: ~0.5 mA → 2000 mAh cell ≈ 167 days without solar.
 */

#include <Wire.h>
#include <SPI.h>
#include <Adafruit_BME280.h>
#include <LoRa.h>
#include <SD.h>
#include <avr/sleep.h>
#include <avr/wdt.h>

// --- Pins ---
#define LORA_CS   10
#define LORA_RST   9
#define LORA_IRQ   2
#define SD_CS      8
#define SENS_PWR   6   // BME280 power via MOSFET
#define SD_PWR     7   // SD card power via MOSFET
#define BATT_ADC  A0

// --- Config ---
#define NODE_ID       1
#define WAKEUPS_PER_CYCLE 37   // 37 × 8 s ≈ 5 min
#define LORA_FREQ  868E6
#define LOG_FILE   "log.csv"

// --- Globals ---
Adafruit_BME280 bme;
volatile uint8_t wdt_count = 0;
uint16_t seq_no = 0;

ISR(WDT_vect) {
  wdt_count++;
}

void wdt_enable_8s() {
  cli();
  wdt_reset();
  MCUSR &= ~(1 << WDRF);
  WDTCSR |= (1 << WDCE) | (1 << WDE);
  WDTCSR = (1 << WDIE) | (1 << WDP3) | (1 << WDP0);  // 8 s interrupt
  sei();
}

void sleep_now() {
  set_sleep_mode(SLEEP_MODE_PWR_DOWN);
  sleep_enable();
  sleep_cpu();
  sleep_disable();
}

struct Payload { uint8_t node_id; uint16_t seq; int16_t temp_x10; uint16_t rh_x10; uint16_t pres_x10; uint16_t batt_mv; };

void setup() {
  Serial.begin(9600);
  Wire.begin();
  SPI.begin();

  pinMode(SENS_PWR, OUTPUT); digitalWrite(SENS_PWR, LOW);
  pinMode(SD_PWR,   OUTPUT); digitalWrite(SD_PWR,   LOW);

  wdt_enable_8s();
  Serial.println(F("Field station boot."));
}

void take_reading_and_transmit() {
  // --- 1. BME280 read ---
  digitalWrite(SENS_PWR, HIGH); delay(100);
  bme.begin(0x76);
  float T   = bme.readTemperature();
  float RH  = bme.readHumidity();
  float P   = bme.readPressure() / 100.0f;  // Pa → hPa
  digitalWrite(SENS_PWR, LOW);

  uint16_t batt_mv = analogRead(BATT_ADC) * 2UL * 3300 / 1023;

  Serial.printf("T=%.1f RH=%.1f P=%.1f Batt=%u mV\n", T, RH, P, batt_mv);

  // --- 2. Log to SD ---
  digitalWrite(SD_PWR, HIGH); delay(50);
  if (SD.begin(SD_CS)) {
    File f = SD.open(LOG_FILE, FILE_WRITE);
    if (f) {
      f.printf("%u,%.2f,%.1f,%.2f,%u\n", seq_no, T, RH, P, batt_mv);
      f.close();
    }
  }
  SD.end();
  digitalWrite(SD_PWR, LOW);

  // --- 3. LoRa transmit ---
  LoRa.setPins(LORA_CS, LORA_RST, LORA_IRQ);
  if (LoRa.begin(LORA_FREQ)) {
    LoRa.setSpreadingFactor(10);
    LoRa.setSignalBandwidth(125E3);
    LoRa.setCodingRate4(5);

    Payload pkt;
    pkt.node_id  = NODE_ID;
    pkt.seq      = seq_no++;
    pkt.temp_x10 = (int16_t)(T  * 10);
    pkt.rh_x10   = (uint16_t)(RH * 10);
    pkt.pres_x10 = (uint16_t)(P  * 10);
    pkt.batt_mv  = batt_mv;

    LoRa.beginPacket();
    LoRa.write((uint8_t*)&pkt, sizeof(pkt));
    LoRa.endPacket();
    LoRa.sleep();
  }
}

void loop() {
  if (wdt_count >= WAKEUPS_PER_CYCLE) {
    wdt_count = 0;
    take_reading_and_transmit();
  }
  sleep_now();
}
